import { describe, it, expect } from 'vitest';
import { edgeCacheMiddleware } from './cache';
import { Context } from 'hono';
import type { AppEnv } from './utils';

describe('cache middleware', () => {
  describe('edgeCacheMiddleware', () => {
    it('creates middleware with default parameters', () => {
      const middleware = edgeCacheMiddleware();
      expect(middleware).toBeTypeOf('function');
    });

    it('creates middleware with custom parameters', () => {
      const middleware = edgeCacheMiddleware(600, 120, 600);
      expect(middleware).toBeTypeOf('function');
    });

    it('sets cache name to aresweb-global-cache', () => {
      // The middleware should use the correct cache name
      const middleware = edgeCacheMiddleware();
      expect(middleware).toBeDefined();
    });

    it('configures cache-control header correctly', () => {
      // Test with custom values
      const middleware = edgeCacheMiddleware(300, 60, 300);

      // Verify the middleware function is created
      expect(middleware).toBeTypeOf('function');

      // The actual cache-control header would be set by the hono/cache wrapper
      // which we can't easily test without a full Hono context
    });

    it('uses s-maxage for CDN caching', () => {
      const middleware = edgeCacheMiddleware(600, 120, 300);

      expect(middleware).toBeTypeOf('function');
    });

    it('includes stale-while-revalidate directive', () => {
      const middleware = edgeCacheMiddleware(300, 60, 600);

      expect(middleware).toBeTypeOf('function');
    });

    it('has sensible default values', () => {
      const middleware = edgeCacheMiddleware();

      expect(middleware).toBeTypeOf('function');
      // Default values: sMaxAge=300, maxAge=60, staleWhileRevalidate=300
    });
  });

  describe('cache behavior', () => {
    it('should be applicable to public API routes', () => {
      const middleware = edgeCacheMiddleware(180, 60, 300);

      expect(middleware).toBeTypeOf('function');
    });

    it('should support different cache durations for different content types', () => {
      // Static content - longer cache
      const staticMiddleware = edgeCacheMiddleware(3600, 600, 3600);
      expect(staticMiddleware).toBeTypeOf('function');

      // Dynamic content - shorter cache
      const dynamicMiddleware = edgeCacheMiddleware(60, 30, 60);
      expect(dynamicMiddleware).toBeTypeOf('function');

      // Real-time content - minimal cache
      const realtimeMiddleware = edgeCacheMiddleware(10, 5, 10);
      expect(realtimeMiddleware).toBeTypeOf('function');
    });
  });
});

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { Context } from 'hono';
import { ZodError } from 'zod';
import {
  errorHandlerMiddleware,
  asyncHandler,
  ApiError,
  throwErrors,
} from './errorHandler';
import { createErrorResponse } from '../../../shared/errors/api';
import type { AppEnv } from './utils';

// Mock the shared errors module
vi.mock('../../../shared/errors/api', () => ({
  createErrorResponse: vi.fn((error: string, code?: string, details?: unknown) => ({
    error,
    ...(code && { code }),
    ...(details !== undefined && { details }),
  })),
  ErrorCode: {
    VALIDATION_ERROR: 'VALIDATION_ERROR',
    UNAUTHORIZED: 'UNAUTHORIZED',
    FORBIDDEN: 'FORBIDDEN',
    NOT_FOUND: 'NOT_FOUND',
    CONFLICT: 'CONFLICT',
    RATE_LIMIT_EXCEEDED: 'RATE_LIMIT_EXCEEDED',
    INTERNAL_SERVER_ERROR: 'INTERNAL_SERVER_ERROR',
  },
}));

describe('errorHandler', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe('ApiError', () => {
    it('creates error with default values', () => {
      const error = new ApiError('Test error');
      expect(error.message).toBe('Test error');
      expect(error.status).toBe(400);
      expect(error.code).toBeUndefined();
      expect(error.details).toBeUndefined();
      expect(error.name).toBe('ApiError');
    });

    it('creates error with custom status code', () => {
      const error = new ApiError('Not found', 404);
      expect(error.message).toBe('Not found');
      expect(error.status).toBe(404);
    });

    it('creates error with code and details', () => {
      const error = new ApiError('Validation failed', 400, 'VALIDATION_ERROR', { field: 'email' });
      expect(error.message).toBe('Validation failed');
      expect(error.status).toBe(400);
      expect(error.code).toBe('VALIDATION_ERROR');
      expect(error.details).toEqual({ field: 'email' });
    });
  });

  describe('errorHandlerMiddleware', () => {
    it('passes through successful requests', async () => {
      const mockContext = {
        req: { path: '/test', method: 'GET' },
        json: vi.fn().mockResolvedValue({ success: true }),
      } as unknown as Context<AppEnv>;

      const next = vi.fn().mockResolvedValue(undefined);

      await errorHandlerMiddleware(mockContext, next);

      expect(next).toHaveBeenCalled();
      expect(mockContext.json).not.toHaveBeenCalled();
    });

    it('handles ApiError correctly', async () => {
      const mockContext = {
        req: { path: '/test', method: 'POST' },
        json: vi.fn().mockReturnThis(),
      } as unknown as Context<AppEnv>;

      const error = new ApiError('Not found', 404, 'NOT_FOUND');
      const next = vi.fn().mockRejectedValue(error);

      await errorHandlerMiddleware(mockContext, next);

      expect(mockContext.json).toHaveBeenCalledWith(
        { error: 'Not found', code: 'NOT_FOUND' },
        404
      );
    });

    it('handles ZodError correctly', async () => {
      const mockContext = {
        req: { path: '/test', method: 'POST' },
        json: vi.fn().mockReturnThis(),
      } as unknown as Context<AppEnv>;

      const zodError = new ZodError([
        {
          code: 'too_small',
          path: ['email'],
          message: 'Email is required',
        },
      ] as never);
      const next = vi.fn().mockRejectedValue(zodError);

      await errorHandlerMiddleware(mockContext, next);

      expect(mockContext.json).toHaveBeenCalledWith(
        expect.objectContaining({
          error: 'Validation failed',
          code: 'VALIDATION_ERROR',
          details: expect.any(Object),
        }),
        400
      );
    });

    it('handles generic Error correctly', async () => {
      const mockContext = {
        req: { path: '/test', method: 'GET' },
        json: vi.fn().mockReturnThis(),
      } as unknown as Context<AppEnv>;

      const error = new Error('Something went wrong');
      const next = vi.fn().mockRejectedValue(error);

      await errorHandlerMiddleware(mockContext, next);

      expect(mockContext.json).toHaveBeenCalledWith(
        { error: 'Something went wrong' },
        500
      );
    });

    it('handles string errors correctly', async () => {
      const mockContext = {
        req: { path: '/test', method: 'GET' },
        json: vi.fn().mockReturnThis(),
      } as unknown as Context<AppEnv>;

      const error = 'String error message';
      const next = vi.fn().mockRejectedValue(error);

      await errorHandlerMiddleware(mockContext, next);

      expect(mockContext.json).toHaveBeenCalledWith(
        { error: 'String error message' },
        500
      );
    });
  });

  describe('asyncHandler', () => {
    it('wraps successful async handlers', async () => {
      const mockContext = {} as Context<AppEnv>;
      const handler = vi.fn().mockResolvedValue({ json: vi.fn().mockReturnValue('success') });

      const wrapped = asyncHandler(handler);
      const result = await wrapped(mockContext);

      expect(handler).toHaveBeenCalledWith(mockContext);
    });

    it('catches ApiError in wrapped handlers', async () => {
      const mockContext = {
        json: vi.fn().mockReturnThis(),
      } as unknown as Context<AppEnv>;

      const handler = vi.fn().mockRejectedValue(new ApiError('Unauthorized', 401, 'UNAUTHORIZED'));

      const wrapped = asyncHandler(handler);
      await wrapped(mockContext);

      expect(mockContext.json).toHaveBeenCalledWith(
        { error: 'Unauthorized', code: 'UNAUTHORIZED' },
        401
      );
    });

    it('catches generic errors in wrapped handlers', async () => {
      const mockContext = {
        json: vi.fn().mockReturnThis(),
      } as unknown as Context<AppEnv>;

      const handler = vi.fn().mockRejectedValue(new Error('Database error'));

      const wrapped = asyncHandler(handler);
      await wrapped(mockContext);

      expect(mockContext.json).toHaveBeenCalledWith(
        { error: 'Database error' },
        500
      );
    });
  });

  describe('throwErrors', () => {
    it('throws bad request error', () => {
      expect(() => throwErrors.badRequest('Invalid input')).toThrow(ApiError);
      try {
        throwErrors.badRequest('Invalid input');
      } catch (e) {
        expect(e).toBeInstanceOf(ApiError);
        expect((e as ApiError).status).toBe(400);
        expect((e as ApiError).message).toBe('Invalid input');
      }
    });

    it('throws bad request error with details', () => {
      try {
        throwErrors.badRequest('Invalid input', { field: 'email' });
      } catch (e) {
        expect((e as ApiError).details).toEqual({ field: 'email' });
      }
    });

    it('throws unauthorized error with default message', () => {
      try {
        throwErrors.unauthorized();
      } catch (e) {
        expect((e as ApiError).status).toBe(401);
        expect((e as ApiError).message).toBe('Unauthorized: Please log in');
      }
    });

    it('throws unauthorized error with custom message', () => {
      try {
        throwErrors.unauthorized('Custom auth message');
      } catch (e) {
        expect((e as ApiError).status).toBe(401);
        expect((e as ApiError).message).toBe('Custom auth message');
      }
    });

    it('throws forbidden error with default message', () => {
      try {
        throwErrors.forbidden();
      } catch (e) {
        expect((e as ApiError).status).toBe(403);
        expect((e as ApiError).message).toBe('Forbidden: Insufficient permissions');
      }
    });

    it('throws not found error with default resource', () => {
      try {
        throwErrors.notFound();
      } catch (e) {
        expect((e as ApiError).status).toBe(404);
        expect((e as ApiError).message).toBe('Resource not found');
      }
    });

    it('throws not found error with custom resource', () => {
      try {
        throwErrors.notFound('Post');
      } catch (e) {
        expect((e as ApiError).status).toBe(404);
        expect((e as ApiError).message).toBe('Post not found');
      }
    });

    it('throws conflict error', () => {
      try {
        throwErrors.conflict('Resource already exists');
      } catch (e) {
        expect((e as ApiError).status).toBe(409);
        expect((e as ApiError).message).toBe('Resource already exists');
      }
    });

    it('throws internal error with default message', () => {
      try {
        throwErrors.internal();
      } catch (e) {
        expect((e as ApiError).status).toBe(500);
        expect((e as ApiError).message).toBe('Internal server error');
      }
    });

    it('throws internal error with custom message', () => {
      try {
        throwErrors.internal('Database connection failed');
      } catch (e) {
        expect((e as ApiError).status).toBe(500);
        expect((e as ApiError).message).toBe('Database connection failed');
      }
    });
  });
});

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { Hono, Context } from 'hono';
import { createContentLifecycleRouter } from './lifecycle';
import type { AppEnv } from './utils';
import type { DrizzleDB } from '../../../src/db/types';

// Mock dependencies
vi.mock('./utils', () => ({
  ensureAdmin: vi.fn(() => async (c: Context, next: () => Promise<void>) => {
    c.set('sessionUser', { id: 'admin-user', role: 'admin', email: 'admin@example.com' });
    await next();
  }),
  getDb: vi.fn((c: Context) => c.get('db')),
  logAuditAction: vi.fn(() => Promise.resolve()),
  AppEnv: {},
}));

vi.mock('drizzle-orm', () => ({
  sql: {
    raw: (str: TemplateStringsArray, ...vals: unknown[]) => ({
      get: () => Promise.resolve({}),
      run: () => Promise.resolve({}),
      execute: () => Promise.resolve({}),
    }),
  },
}));

describe('lifecycle middleware', () => {
  let mockDb: DrizzleDB;
  let mockEnv: AppEnv['Bindings'];
  let mockContext: Context<AppEnv>;

  beforeEach(() => {
    vi.clearAllMocks();

    mockDb = {
      run: vi.fn().mockResolvedValue(undefined),
      insert: vi.fn().mockReturnValue({
        values: vi.fn().mockReturnValue({
          onConflictDoUpdate: vi.fn().mockReturnValue({
            set: vi.fn().mockReturnValue({
              run: vi.fn().mockResolvedValue(undefined),
            }),
          }),
        }),
      }),
    } as unknown as DrizzleDB;

    mockEnv = {
      ENVIRONMENT: 'test',
    } as AppEnv['Bindings'];

    mockContext = {
      req: {
        param: vi.fn((name: string) => {
          if (name === 'id') return 'test-id';
          return null;
        }),
        path: '/api/posts/test-id/approve',
        json: vi.fn().mockResolvedValue({ reason: 'Test reason' }),
      },
      env: mockEnv,
      executionCtx: {
        waitUntil: vi.fn(),
      },
      json: vi.fn().mockReturnThis(),
      get: vi.fn((key: string) => {
        if (key === 'db') return mockDb;
        return undefined;
      }),
      set: vi.fn(),
    } as unknown as Context<AppEnv>;
  });

  describe('createContentLifecycleRouter', () => {
    it('throws error for invalid table name', () => {
      expect(() => {
        createContentLifecycleRouter('invalid_table');
      }).toThrow('[Security] Invalid table or column name in lifecycle router');
    });

    it('throws error for invalid column name', () => {
      expect(() => {
        createContentLifecycleRouter('posts', undefined, 'invalid_column');
      }).toThrow('[Security] Invalid table or column name in lifecycle router');
    });

    it('creates router for valid table and column', () => {
      const router = createContentLifecycleRouter('posts');
      expect(router).toBeDefined();
    });

    it('creates router with custom id column', () => {
      const router = createContentLifecycleRouter('posts', undefined, 'slug');
      expect(router).toBeDefined();
    });
  });

  describe('approve route', () => {
    it('approves content successfully', async () => {
      const router = createContentLifecycleRouter('posts');
      const testContext = {
        ...mockContext,
        req: {
          ...mockContext.req,
          path: '/api/posts/test-id/approve',
          param: vi.fn((name: string) => {
            if (name === 'id') return 'test-id';
            return null;
          }),
        },
      } as unknown as Context<AppEnv>;

      // Simulate route handling
      const handler = router.routes.find((r: unknown) =>
        typeof r === 'object' && r !== null && 'path' in r && r.path === '/:id/approve'
      );
      expect(handler).toBeDefined();
    });

    it('executes custom onApprove hook', async () => {
      const onApproveSpy = vi.fn().mockResolvedValue(true);
      const router = createContentLifecycleRouter('posts', {
        onApprove: onApproveSpy,
      });

      expect(router).toBeDefined();
    });

    it('includes warnings from hook when present', async () => {
      const onApproveSpy = vi.fn().mockResolvedValue({
        handled: true,
        warnings: ['Warning 1', 'Warning 2'],
      });
      const router = createContentLifecycleRouter('posts', {
        onApprove: onApproveSpy,
      });

      expect(router).toBeDefined();
    });
  });

  describe('reject route', () => {
    it('rejects content with reason', async () => {
      const router = createContentLifecycleRouter('posts');
      const testContext = {
        ...mockContext,
        req: {
          ...mockContext.req,
          path: '/api/posts/test-id/reject',
          param: vi.fn((name: string) => {
            if (name === 'id') return 'test-id';
            return null;
          }),
          json: vi.fn().mockResolvedValueOnce({ reason: 'Spam content' }),
        },
      } as unknown as Context<AppEnv>;

      // Simulate route handling
      const handler = router.routes.find((r: unknown) =>
        typeof r === 'object' && r !== null && 'path' in r && r.path === '/:id/reject'
      );
      expect(handler).toBeDefined();
    });

    it('executes custom onReject hook', async () => {
      const onRejectSpy = vi.fn().mockResolvedValue(true);
      const router = createContentLifecycleRouter('posts', {
        onReject: onRejectSpy,
      });

      expect(router).toBeDefined();
    });
  });

  describe('restore route', () => {
    it('restores deleted content', async () => {
      const router = createContentLifecycleRouter('posts');
      const testContext = {
        ...mockContext,
        req: {
          ...mockContext.req,
          path: '/api/posts/test-id/restore',
          param: vi.fn((name: string) => {
            if (name === 'id') return 'test-id';
            return null;
          }),
        },
      } as unknown as Context<AppEnv>;

      const handler = router.routes.find((r: unknown) =>
        typeof r === 'object' && r !== null && 'path' in r && r.path === '/:id/restore'
      );
      expect(handler).toBeDefined();
    });

    it('executes custom onRestore hook', async () => {
      const onRestoreSpy = vi.fn().mockResolvedValue(true);
      const router = createContentLifecycleRouter('posts', {
        onRestore: onRestoreSpy,
      });

      expect(router).toBeDefined();
    });
  });

  describe('soft delete route', () => {
    it('soft deletes content', async () => {
      const router = createContentLifecycleRouter('posts');
      const testContext = {
        ...mockContext,
        req: {
          ...mockContext.req,
          path: '/api/posts/test-id',
          method: 'DELETE',
          param: vi.fn((name: string) => {
            if (name === 'id') return 'test-id';
            return null;
          }),
        },
      } as unknown as Context<AppEnv>;

      const handler = router.routes.find((r: unknown) =>
        typeof r === 'object' && r !== null && 'method' in r && r.method === 'DELETE'
      );
      expect(handler).toBeDefined();
    });

    it('executes custom onDelete hook for trash', async () => {
      const onDeleteSpy = vi.fn().mockResolvedValue(true);
      const router = createContentLifecycleRouter('posts', {
        onDelete: onDeleteSpy,
      });

      expect(router).toBeDefined();
    });

    it('handles errors gracefully', async () => {
      const router = createContentLifecycleRouter('posts');
      const errorDb = {
        ...mockDb,
        run: vi.fn().mockRejectedValue(new Error('Database error')),
      } as unknown as DrizzleDB;

      const testContext = {
        ...mockContext,
        get: vi.fn((key: string) => {
          if (key === 'db') return errorDb;
          return undefined;
        }),
      } as unknown as Context<AppEnv>;

      expect(router).toBeDefined();
    });
  });

  describe('purge route', () => {
    it('hard deletes content', async () => {
      const router = createContentLifecycleRouter('posts');
      const testContext = {
        ...mockContext,
        req: {
          ...mockContext.req,
          path: '/api/posts/test-id/purge',
          method: 'DELETE',
          param: vi.fn((name: string) => {
            if (name === 'id') return 'test-id';
            return null;
          }),
        },
      } as unknown as Context<AppEnv>;

      const handler = router.routes.find((r: unknown) =>
        typeof r === 'object' && r !== null && 'path' in r && r.path === '/:id/purge'
      );
      expect(handler).toBeDefined();
    });

    it('executes custom onDelete hook for purge', async () => {
      const onDeleteSpy = vi.fn().mockResolvedValue(true);
      const router = createContentLifecycleRouter('posts', {
        onDelete: onDeleteSpy,
      });

      expect(router).toBeDefined();
    });
  });

  describe('allowed tables and columns', () => {
    const allowedTables = [
      'posts', 'events', 'docs', 'inquiries', 'users', 'comments',
      'media', 'awards', 'outreach', 'sponsors', 'judges', 'locations',
      'badges', 'user_profiles',
    ];

    it.each(allowedTables)('creates router for %s table', (table) => {
      expect(() => {
        createContentLifecycleRouter(table);
      }).not.toThrow();
    });

    it('creates router with different id columns', () => {
      expect(() => {
        createContentLifecycleRouter('posts', undefined, 'id');
        createContentLifecycleRouter('posts', undefined, 'slug');
        createContentLifecycleRouter('users', undefined, 'user_id');
      }).not.toThrow();
    });
  });

  describe('authentication', () => {
    it('requires admin authentication for all routes', () => {
      const router = createContentLifecycleRouter('posts');

      // All lifecycle routes should have ensureAdmin middleware
      expect(router).toBeDefined();
    });
  });

  describe('audit logging', () => {
    it('logs approve actions', () => {
      const logAuditActionMock = vi.mocked(require('./utils').logAuditAction);
      const router = createContentLifecycleRouter('posts');

      expect(router).toBeDefined();
    });

    it('logs reject actions', () => {
      const router = createContentLifecycleRouter('posts');

      expect(router).toBeDefined();
    });

    it('logs restore actions', () => {
      const router = createContentLifecycleRouter('posts');

      expect(router).toBeDefined();
    });

    it('logs delete actions', () => {
      const router = createContentLifecycleRouter('posts');

      expect(router).toBeDefined();
    });

    it('logs purge actions', () => {
      const router = createContentLifecycleRouter('posts');

      expect(router).toBeDefined();
    });
  });
});

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { generateETag, withETag } from './etag';
import { Context } from 'hono';

describe('etag utility', () => {
  describe('generateETag', () => {
    it('generates ETag for simple object', async () => {
      const data = { foo: 'bar' };
      const etag = await generateETag(data);

      expect(etag).toMatch(/^"[a-f0-9]{64}"$/);
    });

    it('generates consistent ETags for identical data', async () => {
      const data = { name: 'test', value: 123 };
      const etag1 = await generateETag(data);
      const etag2 = await generateETag(data);

      expect(etag1).toBe(etag2);
    });

    it('generates different ETags for different data', async () => {
      const data1 = { name: 'test1' };
      const data2 = { name: 'test2' };
      const etag1 = await generateETag(data1);
      const etag2 = await generateETag(data2);

      expect(etag1).not.toBe(etag2);
    });

    it('handles complex nested objects', async () => {
      const data = {
        user: {
          id: '123',
          profile: {
            name: 'Test User',
            settings: {
              theme: 'dark',
              notifications: true,
            },
          },
        },
      };
      const etag = await generateETag(data);

      expect(etag).toMatch(/^"[a-f0-9]{64}"$/);
    });

    it('handles arrays', async () => {
      const data = [1, 2, 3, 4, 5];
      const etag = await generateETag(data);

      expect(etag).toMatch(/^"[a-f0-9]{64}"$/);
    });

    it('handles arrays of objects', async () => {
      const data = [
        { id: 1, name: 'Item 1' },
        { id: 2, name: 'Item 2' },
      ];
      const etag = await generateETag(data);

      expect(etag).toMatch(/^"[a-f0-9]{64}"$/);
    });

    it('handles null and undefined values', async () => {
      const data1 = { value: null };
      const data2 = { value: undefined };

      const etag1 = await generateETag(data1);
      const etag2 = await generateETag(data2);

      // Both should generate valid ETags
      expect(etag1).toMatch(/^"[a-f0-9]{64}"$/);
      expect(etag2).toMatch(/^"[a-f0-9]{64}"$/);
    });

    it('handles empty objects and arrays', async () => {
      const etag1 = await generateETag({});
      const etag2 = await generateETag([]);

      expect(etag1).toMatch(/^"[a-f0-9]{64}"$/);
      expect(etag2).toMatch(/^"[a-f0-9]{64}"$/);
    });

    it('handles strings', async () => {
      const data = 'simple string';
      const etag = await generateETag(data);

      expect(etag).toMatch(/^"[a-f0-9]{64}"$/);
    });

    it('handles numbers', async () => {
      const data = 42;
      const etag = await generateETag(data);

      expect(etag).toMatch(/^"[a-f0-9]{64}"$/);
    });

    it('handles boolean values', async () => {
      const etag1 = await generateETag(true);
      const etag2 = await generateETag(false);

      expect(etag1).toMatch(/^"[a-f0-9]{64}"$/);
      expect(etag2).toMatch(/^"[a-f0-9]{64}"$/);
      expect(etag1).not.toBe(etag2);
    });
  });

  describe('withETag', () => {
    let mockContext: Context;

    beforeEach(() => {
      mockContext = {
        req: {
          header: vi.fn(),
        },
        header: vi.fn().mockReturnThis(),
        json: vi.fn().mockReturnThis(),
      } as unknown as Context;
    });

    it('sets ETag header on response', async () => {
      const data = { message: 'Hello' };
      mockContext.req.header = vi.fn(() => undefined) as unknown as typeof mockContext.req.header;

      const result = await withETag(mockContext, data);

      expect(mockContext.header).toHaveBeenCalledWith('ETag', expect.stringMatching(/^"[a-f0-9]{64}"$/));
    });

    it('returns 200 when If-None-Match header does not match', async () => {
      const data = { message: 'Hello' };
      mockContext.req.header = vi.fn(() => '"different-etag"') as unknown as typeof mockContext.req.header;
      mockContext.json = vi.fn((body, status) => ({ body, status })) as unknown as typeof mockContext.json;

      const result = await withETag(mockContext, data);

      expect(mockContext.header).toHaveBeenCalled();
    });

    it('returns 304 when If-None-Match header matches', async () => {
      const data = { message: 'Hello' };
      const etag = await generateETag(data);

      mockContext.req.header = vi.fn((name) => {
        if (name === 'If-None-Match') return etag;
        return undefined;
      }) as unknown as typeof mockContext.req.header;
      mockContext.body = vi.fn().mockReturnValue({ status: 304 });

      const result = await withETag(mockContext, data);

      expect(mockContext.body).toHaveBeenCalledWith(null, 304);
    });

    it('handles missing If-None-Match header', async () => {
      const data = { message: 'Hello' };
      mockContext.req.header = vi.fn(() => undefined) as unknown as typeof mockContext.req.header;

      await withETag(mockContext, data);

      expect(mockContext.header).toHaveBeenCalled();
    });

    it('generates consistent ETags across multiple calls with same data', async () => {
      const data = { id: 1, name: 'Test' };

      mockContext.req.header = vi.fn(() => undefined) as unknown as typeof mockContext.req.header;

      await withETag(mockContext, data);
      const firstCall = mockContext.header;

      mockContext.header = vi.fn().mockReturnThis();
      await withETag(mockContext, data);
      const secondCall = mockContext.header;

      expect(firstCall).toHaveBeenCalledWith('ETag', expect.any(String));
      expect(secondCall).toHaveBeenCalledWith('ETag', expect.any(String));
    });
  });

  describe('ETag format', () => {
    it('uses SHA-256 for hash generation (64 hex characters)', async () => {
      const data = { test: 'data' };
      const etag = await generateETag(data);

      // SHA-256 produces 64 hex characters
      const hash = etag.replace(/"/g, '');
      expect(hash).toHaveLength(64);
      expect(hash).toMatch(/^[a-f0-9]{64}$/);
    });

    it('wraps hash in double quotes', async () => {
      const data = { test: 'data' };
      const etag = await generateETag(data);

      expect(etag).toMatch(/^".*"$/);
    });
  });

  describe('edge cases', () => {
    it('handles objects with circular references (via JSON.stringify behavior)', () => {
      const obj: Record<string, unknown> = { name: 'test' };
      obj.self = obj;

      // JSON.stringify would throw for circular refs
      // But since we can't actually test circular refs without throwing,
      // we verify the behavior for deeply nested but valid objects
      const deep: Record<string, unknown> = { level: 1 };
      deep.child = { level: 2, parent: deep };

      // This should still work since JSON.stringify can handle some level of nesting
      expect(async () => {
        // Note: actual circular refs would throw, but this tests the concept
        await generateETag({ level1: { level2: { level3: 'deep' } } });
      }).not.toThrow();
    });

    it('handles special characters in data', async () => {
      const data = {
        message: 'Hello 🌍',
        emoji: '😀',
        unicode: 'Î±Î²Î³Î´',
      };

      const etag = await generateETag(data);
      expect(etag).toMatch(/^"[a-f0-9]{64}"$/);
    });

    it('handles very large data structures', async () => {
      const largeArray = Array.from({ length: 10000 }, (_, i) => ({
        id: i,
        name: `Item ${i}`,
        description: 'A'.repeat(100),
      }));

      const etag = await generateETag(largeArray);
      expect(etag).toMatch(/^"[a-f0-9]{64}"$/);
    });
  });
});

import { describe, it, expect } from 'vitest';
import { toSnakeCase, mapToSnakeCase, camelToSnake } from './caseMapper';

describe('caseMapper utility', () => {
  describe('camelToSnake()', () => {
    it('converts single uppercase word', () => {
      expect(camelToSnake('Date')).toBe('_date');
    });

    it('converts camelCase to snake_case', () => {
      expect(camelToSnake('dateStart')).toBe('date_start');
      expect(camelToSnake('isPotluck')).toBe('is_potluck');
      expect(camelToSnake('firstName')).toBe('first_name');
    });

    it('handles multiple uppercase letters', () => {
      expect(camelToSnake('userID')).toBe('_user_i_d');
      expect(camelToSnake('parseURLToJSON')).toBe('parse_u_r_l_to_json');
    });

    it('returns lowercase for single lowercase word', () => {
      expect(camelToSnake('name')).toBe('name');
    });

    it('handles empty string', () => {
      expect(camelToSnake('')).toBe('');
    });
  });

  describe('toSnakeCase()', () => {
    it('converts camelCase object keys to snake_case', () => {
      const input = { dateStart: '2024-01-01', isPotluck: true };
      const result = toSnakeCase(input);

      expect(result).toHaveProperty('date_start', '2024-01-01');
      expect(result).toHaveProperty('is_potluck', true);
    });

    it('preserves original camelCase keys', () => {
      const input = { firstName: 'John' };
      const result = toSnakeCase(input);

      expect(result).toHaveProperty('first_name', 'John');
      expect(result).toHaveProperty('firstName', 'John');
    });

    it('handles already snake_case keys idempotently', () => {
      const input = { first_name: 'Jane' };
      const result = toSnakeCase(input);

      expect(result).toHaveProperty('first_name', 'Jane');
    });

    it('handles nested values (does not recurse)', () => {
      const input = { user: { name: 'John' } };
      const result = toSnakeCase(input);

      // The nested object itself is preserved as-is
      expect(result.user).toEqual({ name: 'John' });
    });

    it('handles null input', () => {
      expect(toSnakeCase(null as any)).toBe(null);
    });

    it('handles non-object input', () => {
      expect(toSnakeCase('string' as any)).toBe('string');
      expect(toSnakeCase(123 as any)).toBe(123);
    });

    it('handles empty object', () => {
      expect(toSnakeCase({})).toEqual({});
    });

    it('handles mixed camelCase and snake_case', () => {
      const input = {
        firstName: 'John',
        last_name: 'Doe',
        emailAddress: 'john@example.com',
      };
      const result = toSnakeCase(input);

      expect(result.first_name).toBe('John');
      expect(result.last_name).toBe('Doe');
      expect(result.email_address).toBe('john@example.com');
    });
  });

  describe('mapToSnakeCase()', () => {
    it('maps array of objects to snake_case', () => {
      const input = [
        { firstName: 'John', lastName: 'Doe' },
        { firstName: 'Jane', lastName: 'Smith' },
      ];
      const result = mapToSnakeCase(input);

      expect(result[0].first_name).toBe('John');
      expect(result[0].last_name).toBe('Doe');
      expect(result[1].first_name).toBe('Jane');
      expect(result[1].last_name).toBe('Smith');
    });

    it('handles empty array', () => {
      expect(mapToSnakeCase([])).toEqual([]);
    });

    it('handles single element array', () => {
      const input = [{ isActive: true }];
      const result = mapToSnakeCase(input);

      expect(result[0].is_active).toBe(true);
    });
  });
});

import { describe, it, expect } from 'vitest';
import { safeJSONParse, safeJSONStringify } from './json';

describe('JSON utility helpers', () => {
  describe('safeJSONParse()', () => {
    it('returns parsed object for valid JSON string', () => {
      const input = '{"name":"John","age":30}';
      const result = safeJSONParse(input, { default: true });
      expect(result).toEqual({ name: 'John', age: 30 });
    });

    it('returns parsed array for valid JSON array string', () => {
      const input = '[1,2,3,4,5]';
      const result = safeJSONParse<number[]>(input, []);
      expect(result).toEqual([1, 2, 3, 4, 5]);
    });

    it('returns parsed string for valid JSON string', () => {
      const input = '"hello world"';
      const result = safeJSONParse(input, 'default');
      expect(result).toBe('hello world');
    });

    it('returns parsed number for valid JSON number', () => {
      const input = '42';
      const result = safeJSONParse(input, 0);
      expect(result).toBe(42);
    });

    it('returns parsed boolean for valid JSON boolean', () => {
      const input = 'true';
      const result = safeJSONParse(input, false);
      expect(result).toBe(true);
    });

    it('returns parsed null for valid JSON null', () => {
      const input = 'null';
      const result = safeJSONParse(input, 'default');
      expect(result).toBe(null);
    });

    it('returns default value for invalid JSON string', () => {
      const input = '{invalid json}';
      const result = safeJSONParse(input, { default: true });
      expect(result).toEqual({ default: true });
    });

    it('returns default value for malformed JSON object', () => {
      const input = '{"name": "John",}';
      const result = safeJSONParse(input, {});
      expect(result).toEqual({});
    });

    it('returns default value for empty string', () => {
      const result = safeJSONParse('', { default: true });
      expect(result).toEqual({ default: true });
    });

    it('returns default value for non-JSON string', () => {
      const result = safeJSONParse('just plain text', []);
      expect(result).toEqual([]);
    });

    it('returns the value itself when input is not a string', () => {
      const obj = { name: 'John', age: 30 };
      const result = safeJSONParse(obj, { default: true });
      expect(result).toEqual(obj);
    });

    it('returns the value itself when input is a number', () => {
      const result = safeJSONParse(42, 0);
      expect(result).toBe(42);
    });

    it('returns the value itself when input is a boolean', () => {
      const result = safeJSONParse(true, false);
      expect(result).toBe(true);
    });

    it('returns the value itself when input is an array', () => {
      const arr = [1, 2, 3];
      const result = safeJSONParse(arr, []);
      expect(result).toEqual(arr);
    });

    it('returns default value when input is null (non-string)', () => {
      const result = safeJSONParse(null, { default: true });
      expect(result).toEqual({ default: true });
    });

    it('returns default value when input is undefined (non-string)', () => {
      const result = safeJSONParse(undefined, { default: true });
      expect(result).toEqual({ default: true });
    });

    it('handles complex nested objects', () => {
      const input = '{"user":{"name":"John","address":{"city":"Boston"}}}';
      const result = safeJSONParse(input, {});
      expect(result).toEqual({
        user: {
          name: 'John',
          address: { city: 'Boston' }
        }
      });
    });

    it('handles array of objects', () => {
      const input = '[{"id":1,"name":"First"},{"id":2,"name":"Second"}]';
      const result = safeJSONParse(input, []);
      expect(result).toEqual([
        { id: 1, name: 'First' },
        { id: 2, name: 'Second' }
      ]);
    });

    it('type inference works correctly', () => {
      const input = '{"value":123}';
      const result = safeJSONParse<{ value: number }>(input, { value: 0 });
      expect(result.value).toBe(123);
    });
  });

  describe('safeJSONStringify()', () => {
    it('returns JSON string for valid object', () => {
      const input = { name: 'John', age: 30 };
      const result = safeJSONStringify(input);
      expect(result).toBe('{"name":"John","age":30}');
    });

    it('returns JSON string for valid array', () => {
      const input = [1, 2, 3, 4, 5];
      const result = safeJSONStringify(input);
      expect(result).toBe('[1,2,3,4,5]');
    });

    it('returns string as-is when input is already a string', () => {
      const input = 'already a string';
      const result = safeJSONStringify(input);
      expect(result).toBe('already a string');
    });

    it('returns JSON string for number', () => {
      const result = safeJSONStringify(42);
      expect(result).toBe('42');
    });

    it('returns JSON string for boolean true', () => {
      const result = safeJSONStringify(true);
      expect(result).toBe('true');
    });

    it('returns JSON string for boolean false', () => {
      const result = safeJSONStringify(false);
      expect(result).toBe('false');
    });

    it('returns default string for null input', () => {
      const result = safeJSONStringify(null);
      expect(result).toBe('[]');
    });

    it('returns default string for undefined input', () => {
      const result = safeJSONStringify(undefined);
      expect(result).toBe('[]');
    });

    it('returns custom default string for null input', () => {
      const result = safeJSONStringify(null, '{}');
      expect(result).toBe('{}');
    });

    it('returns custom default string for undefined input', () => {
      const result = safeJSONStringify(undefined, 'null');
      expect(result).toBe('null');
    });

    it('returns default string for circular reference', () => {
      const obj: Record<string, unknown> = { name: 'test' };
      obj.self = obj;
      const result = safeJSONStringify(obj);
      expect(result).toBe('[]');
    });

    it('returns custom default string for circular reference', () => {
      const obj: Record<string, unknown> = { name: 'test' };
      obj.self = obj;
      const result = safeJSONStringify(obj, 'custom-default');
      expect(result).toBe('custom-default');
    });

    it('handles nested objects', () => {
      const input = {
        user: {
          name: 'John',
          address: {
            city: 'Boston',
            zip: '02108'
          }
        }
      };
      const result = safeJSONStringify(input);
      expect(result).toBe('{"user":{"name":"John","address":{"city":"Boston","zip":"02108"}}}');
    });

    it('handles array of objects', () => {
      const input = [
        { id: 1, name: 'First' },
        { id: 2, name: 'Second' }
      ];
      const result = safeJSONStringify(input);
      expect(result).toBe('[{"id":1,"name":"First"},{"id":2,"name":"Second"}]');
    });

    it('handles empty object', () => {
      const result = safeJSONStringify({});
      expect(result).toBe('{}');
    });

    it('handles empty array', () => {
      const result = safeJSONStringify([]);
      expect(result).toBe('[]');
    });

    it('handles special characters in strings', () => {
      const input = { message: 'Hello "World"!\nNew line' };
      const result = safeJSONStringify(input);
      expect(result).toBe('{"message":"Hello \\"World\\"!\\nNew line"}');
    });

    it('handles unicode characters', () => {
      const input = { emoji: '😀', chinese: '你好' };
      const result = safeJSONStringify(input);
      expect(result).toBe('{"emoji":"😀","chinese":"你好"}');
    });

    it('handles Date objects', () => {
      const date = new Date('2026-05-08T12:00:00Z');
      const result = safeJSONStringify({ date });
      // Date objects get stringified to ISO format
      expect(result).toContain('"date":"2026-05-08T');
    });

    it('respects custom default parameter', () => {
      const result = safeJSONStringify(null, 'custom-default');
      expect(result).toBe('custom-default');
    });

    it('uses [] as default default string', () => {
      const result = safeJSONStringify(null);
      expect(result).toBe('[]');
    });

    it('handles bigint gracefully (throws on stringify)', () => {
      const input = { value: BigInt(123) };
      const result = safeJSONStringify(input, 'fallback');
      expect(result).toBe('fallback');
    });

    it('ignores symbol-keyed properties (stringifies as empty object)', () => {
      const input = { [Symbol('test')]: 'value' };
      const result = safeJSONStringify(input, 'fallback');
      // Symbol keys are ignored by JSON.stringify, resulting in {}
      expect(result).toBe('{}');
    });
  });

  describe('integration: parse and stringify roundtrip', () => {
    it('roundtrips an object correctly', () => {
      const original = { name: 'John', age: 30, active: true };
      const stringified = safeJSONStringify(original);
      const parsed = safeJSONParse(stringified, {});
      expect(parsed).toEqual(original);
    });

    it('roundtrips an array correctly', () => {
      const original = [1, 2, 3, 'four', { five: 5 }];
      const stringified = safeJSONStringify(original);
      const parsed = safeJSONParse<typeof original>(stringified, []);
      expect(parsed).toEqual(original);
    });

    it('handles empty object roundtrip', () => {
      const original = {};
      const stringified = safeJSONStringify(original);
      const parsed = safeJSONParse(stringified, null);
      expect(parsed).toEqual(original);
    });

    it('handles empty array roundtrip', () => {
      const original: unknown[] = [];
      const stringified = safeJSONStringify(original);
      const parsed = safeJSONParse(original, []);
      expect(parsed).toEqual(original);
    });
  });
});

