    renderWithRouter(<MemberCard member={mockMember} />);

    expect(screen.getByText("TestUser")).toBeInTheDocument();
    expect(screen.getByText("they/them")).toBeInTheDocument();
  });

  it("falls back to name when nickname is not available", () => {
