    expect(badges.length).toBe(0);
  });

  it("limits subteams display to 3 items", () => {
    const memberWithManySubteams: TeamMember = {
      ...mockMember,
      subteams: ["Software", "Electronics", "Mechanical", "Business", "Design"],
