/**
 * Unit tests for useRichEditor hook
 * Comprehensive coverage of Tiptap editor initialization including:
 * - Editor creation with default options
 * - Custom placeholder configuration
 * - Yjs collaboration integration
 * - Extension loading
 * - Editor cleanup
 * - Lowlight syntax highlighting configuration
 */

import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
import { renderHook, waitFor } from "@testing-library/react";
import { useRichEditor } from "./useRichEditor";
import * as React from "react";
import { createLowlight, common } from "lowlight";
import * as Y from "yjs";

// Mock @tiptap/react
const mockEditor = {
  isEditable: true,
  isEmpty: false,
  getHTML: vi.fn(() => "<p>Test content</p>"),
  getText: vi.fn(() => "Test content"),
  destroy: vi.fn(),
  commands: {
    setContent: vi.fn(),
    clearContent: vi.fn(),
    focus: vi.fn(),
    blur: vi.fn(),
  },
  extensionManager: {
    extensions: [],
  },
};

const mockUseEditor = vi.fn(() => mockEditor);

vi.mock("@tiptap/react", () => ({
  useEditor: mockUseEditor,
  Editor: class MockEditor {},
}));

// Mock lowlight
vi.mock("lowlight", () => ({
  common: {
    javascript: "javascript",
    typescript: "typescript",
    python: "python",
    css: "css",
    html: "html",
  },
  createLowlight: vi.fn((languages) => ({
    languages,
    highlight: vi.fn(() => ({
      value: "<span>highlighted</span>",
    })),
  })),
}));

// Mock yjs
vi.mock("yjs", () => ({
  Doc: vi.fn(() => ({
    getText: vi.fn(() => ({
      toString: vi.fn(() => ""),
      insert: vi.fn(),
      delete: vi.fn(),
    })),
    getMap: vi.fn(() => new Map()),
    on: vi.fn(),
    off: vi.fn(),
  })),
}));

describe("useRichEditor", () => {
  let createLowlightMock: any;

  beforeEach(async () => {
    vi.clearAllMocks();

    // Import and mock createLowlight
    const lowlightModule = await import("lowlight");
    createLowlightMock = vi.spyOn(lowlightModule, "createLowlight");
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  describe("initialization", () => {
    it("should create editor with default placeholder", () => {
      const { result } = renderHook(() => useRichEditor());

      expect(mockUseEditor).toHaveBeenCalledWith(
        expect.objectContaining({
          content: "<p>Start writing here...</p>",
          editorProps: expect.objectContaining({
            attributes: expect.objectContaining({
              class: "prose prose-invert max-w-none focus:outline-none min-h-[400px] text-[#e6edf3] font-mono",
              spellcheck: "true",
            }),
          }),
        })
      );

      expect(result.current).toBeDefined();
    });

    it("should create editor with custom placeholder", () => {
      const customPlaceholder = "<p>Enter your blog post...</p>";
      const { result } = renderHook(() =>
        useRichEditor({ placeholder: customPlaceholder })
      );

      expect(mockUseEditor).toHaveBeenCalledWith(
        expect.objectContaining({
          content: customPlaceholder,
        })
      );

      expect(result.current).toBeDefined();
    });

    it("should create lowlight instance with common languages", () => {
      renderHook(() => useRichEditor());

      expect(createLowlightMock).toHaveBeenCalledWith(expect.any(Object));
    });

    it("should return null editor during initialization", () => {
      mockUseEditor.mockReturnValueOnce(null as any);

      const { result } = renderHook(() => useRichEditor());

      expect(result.current).toBeNull();
    });

    it("should return editor instance after initialization", () => {
      const { result } = renderHook(() => useRichEditor());

      expect(result.current).toBeDefined();
    });
  });

  describe("Yjs collaboration", () => {
    it("should not set content when Ydoc is provided", () => {
      const mockYDoc = new Y.Doc();

      renderHook(() =>
        useRichEditor({
          ydoc: mockYDoc,
          yfield: "prosemirror",
        })
      );

      expect(mockUseEditor).toHaveBeenCalledWith(
        expect.objectContaining({
          content: undefined,
        })
      );
    });

    it("should include yfield in extensions when provided", () => {
      const mockYDoc = new Y.Doc();
      const mockProvider = {};

      renderHook(() =>
        useRichEditor({
          ydoc: mockYDoc,
          provider: mockProvider,
          yfield: "custom-field",
        })
      );

      expect(mockUseEditor).toHaveBeenCalled();
      const extensions = (mockUseEditor as any).mock.calls[0][0].extensions;
      expect(extensions).toBeDefined();
      expect(Array.isArray(extensions)).toBe(true);
    });

    it("should work with default yfield", () => {
      const mockYDoc = new Y.Doc();

      renderHook(() =>
        useRichEditor({
          ydoc: mockYDoc,
        })
      );

      expect(mockUseEditor).toHaveBeenCalled();
    });

    it("should include provider when available", () => {
      const mockYDoc = new Y.Doc();
      const mockProvider = {
        room: {
          getSelf: vi.fn(() => ({
            info: { name: "Test User" },
          })),
        },
      };

      renderHook(() =>
        useRichEditor({
          ydoc: mockYDoc,
          provider: mockProvider,
          yfield: "default",
        })
      );

      expect(mockUseEditor).toHaveBeenCalled();
    });
  });

  describe("editor attributes", () => {
    it("should apply correct CSS classes", () => {
      renderHook(() => useRichEditor());

      const editorProps = (mockUseEditor as any).mock.calls[0][0].editorProps;

      expect(editorProps.attributes.class).toContain("prose");
      expect(editorProps.attributes.class).toContain("prose-invert");
      expect(editorProps.attributes.class).toContain("max-w-none");
      expect(editorProps.attributes.class).toContain("focus:outline-none");
      expect(editorProps.attributes.class).toContain("min-h-[400px]");
      expect(editorProps.attributes.class).toContain("text-[#e6edf3]");
      expect(editorProps.attributes.class).toContain("font-mono");
    });

    it("should enable spellcheck", () => {
      renderHook(() => useRichEditor());

      const editorProps = (mockUseEditor as any).mock.calls[0][0].editorProps;

      expect(editorProps.attributes.spellcheck).toBe("true");
    });
  });

  describe("extensions", () => {
    it("should load editor extensions", () => {
      renderHook(() => useRichEditor());

      const extensions = (mockUseEditor as any).mock.calls[0][0].extensions;

      expect(extensions).toBeDefined();
      expect(Array.isArray(extensions)).toBe(true);
      expect(extensions.length).toBeGreaterThan(0);
    });

    it("should include collaboration extensions when Ydoc is provided", () => {
      const mockYDoc = new Y.Doc();

      renderHook(() =>
        useRichEditor({
          ydoc: mockYDoc,
        })
      );

      const extensions = (mockUseEditor as any).mock.calls[0][0].extensions;

      // Should have collaboration extensions
      expect(extensions.length).toBeGreaterThan(0);
    });

    it("should include cursor extension when provider is provided", () => {
      const mockYDoc = new Y.Doc();
      const mockProvider = {
        room: {
          getSelf: vi.fn(() => ({
            info: { name: "Test User" },
          })),
        },
      };

      renderHook(() =>
        useRichEditor({
          ydoc: mockYDoc,
          provider: mockProvider,
          yfield: "default",
        })
      );

      const extensions = (mockUseEditor as any).mock.calls[0][0].extensions;

      // Should have cursor extension when provider is present
      expect(extensions.length).toBeGreaterThan(0);
    });
  });

  describe("memoization", () => {
    it("should memoize lowlight instance", () => {
      const { rerender } = renderHook(() => useRichEditor());

      const firstCallCount = createLowlightMock.mock.calls.length;

      rerender();

      const secondCallCount = createLowlightMock.mock.calls.length;

      // Lowlight should only be created once due to useMemo
      expect(secondCallCount).toBe(firstCallCount);
    });

    it("should update extensions when ydoc changes", () => {
      const mockYDoc1 = new Y.Doc();
      const mockYDoc2 = new Y.Doc();

      const { rerender } = renderHook(
        ({ ydoc }) => useRichEditor({ ydoc }),
        { initialProps: { ydoc: mockYDoc1 } }
      );

      const firstExtensions = (mockUseEditor as any).mock.calls[0][0].extensions;

      rerender({ ydoc: mockYDoc2 });

      // After rerender with new ydoc, check if useEditor was called again
      expect(mockUseEditor).toHaveBeenCalled();
    });
  });

  describe("editor lifecycle", () => {
    it("should handle editor cleanup on unmount", () => {
      const { unmount } = renderHook(() => useRichEditor());

      // Editor should be created
      expect(mockUseEditor).toHaveBeenCalled();

      // Unmount should trigger cleanup
      unmount();

      // The mock editor's destroy should be called by Tiptap internally
      // We're just verifying the hook doesn't throw during unmount
      expect(true).toBe(true);
    });

    it("should handle re-rendering without issues", () => {
      const { rerender } = renderHook(() => useRichEditor());

      // Should not throw on rerender
      expect(() => rerender()).not.toThrow();
    });
  });

  describe("edge cases", () => {
    it("should handle empty string placeholder", () => {
      const { result } = renderHook(() =>
        useRichEditor({ placeholder: "" })
      );

      expect(result.current).toBeDefined();
      expect(mockUseEditor).toHaveBeenCalledWith(
        expect.objectContaining({
          content: "",
        })
      );
    });

    it("should handle undefined yfield", () => {
      const mockYDoc = new Y.Doc();

      const { result } = renderHook(() =>
        useRichEditor({
          ydoc: mockYDoc,
          // yfield is undefined
        })
      );

      expect(result.current).toBeDefined();
    });

    it("should handle null provider", () => {
      const mockYDoc = new Y.Doc();

      const { result } = renderHook(() =>
        useRichEditor({
          ydoc: mockYDoc,
          provider: null,
        })
      );

      expect(result.current).toBeDefined();
    });

    it("should handle options object with no properties", () => {
      const { result } = renderHook(() => useRichEditor({}));

      expect(result.current).toBeDefined();
    });
  });

  describe("integration scenarios", () => {
    it("should work with all Yjs collaboration options", () => {
      const mockYDoc = new Y.Doc();
      const mockProvider = {
        room: {
          getSelf: vi.fn(() => ({
            info: { name: "Collaborator" },
          })),
        },
      };

      const { result } = renderHook(() =>
        useRichEditor({
          placeholder: "<p>Collaborative document...</p>",
          ydoc: mockYDoc,
          provider: mockProvider,
          yfield: "shared-doc",
        })
      );

      expect(result.current).toBeDefined();
      expect(mockUseEditor).toHaveBeenCalledWith(
        expect.objectContaining({
          content: undefined, // No initial content with Yjs
        })
      );
    });

    it("should work in standalone mode without collaboration", () => {
      const { result } = renderHook(() =>
        useRichEditor({
          placeholder: "<p>My blog post...</p>",
        })
      );

      expect(result.current).toBeDefined();
      expect(mockUseEditor).toHaveBeenCalledWith(
        expect.objectContaining({
          content: "<p>My blog post...</p>",
        })
      );
    });
  });

  describe("editor attributes accessibility", () => {
    it("should include accessible markup attributes", () => {
      renderHook(() => useRichEditor());

      const editorProps = (mockUseEditor as any).mock.calls[0][0].editorProps;

      // Verify attributes object is properly structured
      expect(editorProps).toBeDefined();
      expect(editorProps.attributes).toBeDefined();
      expect(typeof editorProps.attributes.class).toBe("string");
      expect(typeof editorProps.attributes.spellcheck).toBe("string");
    });
  });
});

import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
import { render, screen, fireEvent, waitFor } from "@testing-library/react";
import ConfirmModal from "./ConfirmModal";

describe("ConfirmModal Component", () => {
  let mockConfirm: ReturnType<typeof vi.fn>;
  let mockCancel: ReturnType<typeof vi.fn>;

  beforeEach(() => {
    mockConfirm = vi.fn();
    mockCancel = vi.fn();
    // Mock getBoundingClientRect for framer-motion measurements
    Element.prototype.getBoundingClientRect = vi.fn(() => ({
      width: 400,
      height: 200,
      top: 0,
      left: 0,
      bottom: 200,
      right: 400,
      x: 0,
      y: 0,
      toJSON: vi.fn(),
    }));
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  it("renders when isOpen is true", () => {
    render(
      <ConfirmModal
        isOpen={true}
        onConfirm={mockConfirm}
        onCancel={mockCancel}
        description="Are you sure you want to proceed?"
      />
    );

    expect(screen.getByText("Are you sure you want to proceed?")).toBeInTheDocument();
    expect(screen.getByRole("alertdialog")).toBeInTheDocument();
  });

  it("does not render when isOpen is false", () => {
    const { container } = render(
      <ConfirmModal
        isOpen={false}
        onConfirm={mockConfirm}
        onCancel={mockCancel}
        description="Are you sure?"
      />
    );

    expect(screen.queryByRole("alertdialog")).not.toBeInTheDocument();
    expect(container.firstChild).toBe(null);
  });

  it("renders custom title", () => {
    render(
      <ConfirmModal
        isOpen={true}
        title="Delete Item"
        onConfirm={mockConfirm}
        onCancel={mockCancel}
        description="This action cannot be undone."
      />
    );

    expect(screen.getByText("Delete Item")).toBeInTheDocument();
  });

  it("renders default title when none provided", () => {
    render(
      <ConfirmModal
        isOpen={true}
        onConfirm={mockConfirm}
        onCancel={mockCancel}
        description="Test description"
      />
    );

    expect(screen.getByText("Confirm Action")).toBeInTheDocument();
  });

  it("renders custom button text", () => {
    render(
      <ConfirmModal
        isOpen={true}
        confirmText="Delete"
        cancelText="Keep"
        onConfirm={mockConfirm}
        onCancel={mockCancel}
        description="Delete this item?"
      />
    );

    expect(screen.getByText("Delete")).toBeInTheDocument();
    expect(screen.getByText("Keep")).toBeInTheDocument();
  });

  it("calls onConfirm when confirm button is clicked", () => {
    render(
      <ConfirmModal
        isOpen={true}
        onConfirm={mockConfirm}
        onCancel={mockCancel}
        description="Confirm this action?"
      />
    );

    const confirmButton = screen.getByText("Confirm");
    fireEvent.click(confirmButton);
    expect(mockConfirm).toHaveBeenCalledTimes(1);
  });

  it("calls onCancel when cancel button is clicked", () => {
    render(
      <ConfirmModal
        isOpen={true}
        onConfirm={mockConfirm}
        onCancel={mockCancel}
        description="Cancel this action?"
      />
    );

    const cancelButton = screen.getByText("Cancel");
    fireEvent.click(cancelButton);
    expect(mockCancel).toHaveBeenCalledTimes(1);
  });

  it("calls onCancel when backdrop is clicked", () => {
    render(
      <ConfirmModal
        isOpen={true}
        onConfirm={mockConfirm}
        onCancel={mockCancel}
        description="Click outside to cancel"
      />
    );

    const backdrop = screen.getByText("Confirm this action?").closest("div")?.parentElement;
    if (backdrop) {
      fireEvent.click(backdrop);
      expect(mockCancel).toHaveBeenCalledTimes(1);
    }
  });

  it("applies destructive styling when destructive prop is true", () => {
    const { container } = render(
      <ConfirmModal
        isOpen={true}
        destructive={true}
        onConfirm={mockConfirm}
        onCancel={mockCancel}
        description="Destructive action"
      />
    );

    const confirmButton = screen.getByText("Confirm");
    expect(confirmButton).toHaveClass("bg-ares-danger/20");
  });

  it("applies non-destructive styling when destructive prop is false", () => {
    const { container } = render(
      <ConfirmModal
        isOpen={true}
        destructive={false}
        onConfirm={mockConfirm}
        onCancel={mockCancel}
        description="Safe action"
      />
    );

    const confirmButton = screen.getByText("Confirm");
    expect(confirmButton).toHaveClass("bg-ares-cyan/20");
  });

  it("calls onCancel when Escape key is pressed", () => {
    render(
      <ConfirmModal
        isOpen={true}
        onConfirm={mockConfirm}
        onCancel={mockCancel}
        description="Press escape to cancel"
      />
    );

    fireEvent.keyDown(document, { key: "Escape" });
    expect(mockCancel).toHaveBeenCalledTimes(1);
  });

  it("calls onConfirm when Enter key is pressed", () => {
    render(
      <ConfirmModal
        isOpen={true}
        onConfirm={mockConfirm}
        onCancel={mockCancel}
        description="Press enter to confirm"
      />
    );

    fireEvent.keyDown(document, { key: "Enter" });
    expect(mockConfirm).toHaveBeenCalledTimes(1);
  });

  it("implements focus trap with Tab key", () => {
    render(
      <ConfirmModal
        isOpen={true}
        onConfirm={mockConfirm}
        onCancel={mockCancel}
        description="Focus trap test"
      />
    );

    const buttons = screen.getAllByRole("button");
    const firstButton = buttons[0];
    const lastButton = buttons[buttons.length - 1];

    // Focus first button
    firstButton.focus();
    expect(document.activeElement).toBe(firstButton);

    // Press Shift+Tab to move to last button
    fireEvent.keyDown(document, { key: "Tab", shiftKey: true });
    // Note: Focus trap behavior is complex to test in jsdom,
    // but we verify the handler doesn't crash
    expect(mockCancel).not.toHaveBeenCalled();
  });

  it("auto-focuses confirm button on open", async () => {
    render(
      <ConfirmModal
        isOpen={true}
        onConfirm={mockConfirm}
        onCancel={mockCancel}
        description="Auto focus test"
      />
    );

    await waitFor(() => {
      const buttons = screen.getAllByRole("button");
      const confirmButton = buttons.find(btn => btn.textContent === "Confirm");
      expect(confirmButton).toHaveFocus();
    }, { timeout: 100 });
  });

  it("has proper ARIA attributes", () => {
    render(
      <ConfirmModal
        isOpen={true}
        title="Test Title"
        onConfirm={mockConfirm}
        onCancel={mockCancel}
        description="Test description"
      />
    );

    const dialog = screen.getByRole("alertdialog");
    expect(dialog).toHaveAttribute("aria-modal", "true");
    expect(dialog).toHaveAttribute("aria-labelledby", "confirm-modal-title");
    expect(dialog).toHaveAttribute("aria-describedby", "confirm-modal-desc");

    expect(screen.getByText("Test Title").parentElement).toHaveAttribute("id", "confirm-modal-title");
    expect(screen.getByText("Test description").parentElement).toHaveAttribute("id", "confirm-modal-desc");
  });
});

