      const { result } = renderHook(() => useDocs("test-slug"), { wrapper });

      const categories = result.current.groupedDocs.map(([cat]) => cat);
      expect(categories).toEqual([
        "Getting Started",
        "Migration Guides",
        "Support",
        "Community",
        "Reference",
      ]);
    });

    it("should append categories not in SIDEBAR_ORDER at the end", () => {
